import urllib.request
import json

headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}

def fetch_news(source_name, url):
    try:
        req = urllib.request.Request(url, headers=headers)
        with urllib.request.urlopen(req, timeout=10) as response:
            data = json.loads(response.read().decode())
            return source_name, data.get('items', [])[:5]
    except Exception as e:
        return source_name, []

def main():
    sources = [
        ("TechCrunch", "https://api.rss2json.com/v1/api.json?rss_url=https://techcrunch.com/feed/"),
        ("The Verge", "https://api.rss2json.com/v1/api.json?rss_url=https://www.theverge.com/tech/rss/index.xml"),
        ("Ars Technica", "https://api.rss2json.com/v1/api.json?rss_url=https://arstechnica.com/science/feed/"),
    ]

    all_news = []
    for name, url in sources:
        source_name, news_items = fetch_news(name, url)
        if news_items:
            all_news.append((source_name, news_items))

    print("=" * 60)
    print("TOP TECHNOLOGY NEWS SUMMARY")
    print("=" * 60)

    for source_name, news_items in all_news:
        print(f"\n{source_name.upper()}")
        print("-" * 40)
        for item in news_items:
            print(f"\n• {item['title']}")
            print(f"  Source: {item['link']}")

    return all_news

if __name__ == "__main__":
    main()

